VALUES
  ('optometrist-moex-00324', 'optometrist', 'optometrist-moex-113-b0a2f330', 'sub-optometrist-02', NULL, 'single_choice', '有關視網膜神經傳導訊息的先後順序，下列何者正確？', '["感光細胞（photoreceptorcell）→神經節細胞（ganglioncell）→雙極細胞（bipolarcell）", "雙極細胞→感光細胞→神經節細胞", "感光細胞→雙極細胞→神經節細胞", "神經節細胞→感光細胞→雙極細胞"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:40+00:00", "source_pdf_sha1": "87d2d58d5233", "answer_pdf_sha1": "d9cba2739812", "source_family": "moex-gov-tw", "moex": {"exam_code": "113100", "c": "109", "s": "0901", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "眼球解剖生理學與倫理法規", "year": "113", "exam_name": "113年第二次專技人員高等考試營養師、護理師、社會工作師考試、113年專技人員高等考試心理師、法醫師、語言治療師、聽力師、牙體技術師、公共衛...", "original_question_number": 19, "answer_corrected": false, "flags": [], "slug": "optometrist", "db_exam_id": "optometrist"}'::jsonb, NULL),
  ('optometrist-moex-00325', 'optometrist', 'optometrist-moex-113-b0a2f330', 'sub-optometrist-02', NULL, 'single_choice', '有關眼外肌的神經支配的敘述，下列何者正確？', '["外直肌是由第六對腦神經（外展神經，abducens nerve, CN Ⅵ）支配，右側的第六對腦神經核支配左 側的外直肌", "內直肌是由第四對腦神經（滑車神經，trochlear nerve, CN Ⅳ）支配，右側的第四對腦神經核支配右 側的內直肌", "下斜肌是由第三對腦神經（動眼神經，oculomotor nerve, CN Ⅲ）支配，右側的第三對腦神經核支配 左側的下斜肌", "上斜肌是由第四對腦神經（滑車神經，trochlear nerve, CN Ⅳ）支配，右側的第四對腦神經核支配左 側的上斜肌"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:40+00:00", "source_pdf_sha1": "87d2d58d5233", "answer_pdf_sha1": "d9cba2739812", "source_family": "moex-gov-tw", "moex": {"exam_code": "113100", "c": "109", "s": "0901", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "眼球解剖生理學與倫理法規", "year": "113", "exam_name": "113年第二次專技人員高等考試營養師、護理師、社會工作師考試、113年專技人員高等考試心理師、法醫師、語言治療師、聽力師、牙體技術師、公共衛...", "original_question_number": 20, "answer_corrected": false, "flags": [], "slug": "optometrist", "db_exam_id": "optometrist"}'::jsonb, NULL),
  ('optometrist-moex-00326', 'optometrist', 'optometrist-moex-113-b0a2f330', 'sub-optometrist-02', NULL, 'single_choice', '上斜肌的長度很長，從眼窩尖（orbitalapex）出發後會穿過眼窩壁內上方的滑車（trochlea），再向後、 下行走，最後附著在眼球上方的後外側。有關上斜肌的敘述，下列何者錯誤？', '["滑車處發炎也會引起斜視，此種症狀稱為布朗症候群（Brownsyndrome）", "上斜肌由第四對腦神經支配", "上斜肌的運動作用方向包括下舉（depression）、內旋（incyclotorsion）以及內轉（adduction）", "上斜肌最後附著在眼球上的位置，其肌肉路徑方向與第一眼位（primaryposition）的視軸比較，夾 角約為55度"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:40+00:00", "source_pdf_sha1": "87d2d58d5233", "answer_pdf_sha1": "d9cba2739812", "source_family": "moex-gov-tw", "moex": {"exam_code": "113100", "c": "109", "s": "0901", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "眼球解剖生理學與倫理法規", "year": "113", "exam_name": "113年第二次專技人員高等考試營養師、護理師、社會工作師考試、113年專技人員高等考試心理師、法醫師、語言治療師、聽力師、牙體技術師、公共衛...", "original_question_number": 21, "answer_corrected": false, "flags": [], "slug": "optometrist", "db_exam_id": "optometrist"}'::jsonb, NULL),
  ('optometrist-moex-00327', 'optometrist', 'optometrist-moex-113-b0a2f330', 'sub-optometrist-02', NULL, 'single_choice', '麻痺性斜視病人兩眼的偏移程度，常會隨著不同的注視（gaze）方位而不同，這種斜視稱為下列何者？', '["隱斜視（latentstrabismus）", "顯斜視（manifeststrabismus）", "非共同性斜視（incomitantstrabismus）", "共同性斜視（concomitantstrabismus）"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:40+00:00", "source_pdf_sha1": "87d2d58d5233", "answer_pdf_sha1": "d9cba2739812", "source_family": "moex-gov-tw", "moex": {"exam_code": "113100", "c": "109", "s": "0901", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "眼球解剖生理學與倫理法規", "year": "113", "exam_name": "113年第二次專技人員高等考試營養師、護理師、社會工作師考試、113年專技人員高等考試心理師、法醫師、語言治療師、聽力師、牙體技術師、公共衛...", "original_question_number": 22, "answer_corrected": false, "flags": [], "slug": "optometrist", "db_exam_id": "optometrist"}'::jsonb, NULL),
  ('optometrist-moex-00328', 'optometrist', 'optometrist-moex-113-b0a2f330', 'sub-optometrist-02', NULL, 'single_choice', '有關視網膜循環系統之敘述，下列何者正確？①糖尿病患者的血管病變可能發生在中心視網膜動靜脈', '["虹膜動脈小環（minorarterialcircleoftheiris）的分支被拉扯破壞滲漏是造成玻璃體出血 原因", "位於小窩（fovea）區域匯出的中心視網膜動脈分支內徑大且流速最快", "位於小窩區域的脈 絡膜血管流速最快，且自律神徑可支配脈絡膜血管系統的運作  ⑤中心視網膜動靜脈分支與視網膜組 織層區域的細胞具有血液視網膜屏障（blood-retinalbarrier,BRB）特徵", "僅"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:40+00:00", "source_pdf_sha1": "87d2d58d5233", "answer_pdf_sha1": "d9cba2739812", "source_family": "moex-gov-tw", "moex": {"exam_code": "113100", "c": "109", "s": "0901", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "眼球解剖生理學與倫理法規", "year": "113", "exam_name": "113年第二次專技人員高等考試營養師、護理師、社會工作師考試、113年專技人員高等考試心理師、法醫師、語言治療師、聽力師、牙體技術師、公共衛...", "original_question_number": 23, "answer_corrected": false, "flags": [], "slug": "optometrist", "db_exam_id": "optometrist"}'::jsonb, NULL),
  ('optometrist-moex-00329', 'optometrist', 'optometrist-moex-113-b0a2f330', 'sub-optometrist-02', NULL, 'single_choice', '有關眼循環系統之敘述，下列何者錯誤？', '["眼球赤道後方的脈絡膜之血管供應主要來自短後睫狀動脈（shortposteriorciliaryartery）", "睫狀體（ciliarybody）的血液供應主要來自長後睫狀動脈（longposteriorciliaryartery）", "虹膜大動脈環（majorarterialcircleoftheiris）是由前睫動脈（anteriorciliaryartery）與長後睫狀動 脈匯集而成，位於虹膜根部（irisroot）", "虹膜小血管環（minorvascularcircleoftheiris）位於虹彩，是虹彩動脈與靜脈的吻合處（anastomoses）"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:40+00:00", "source_pdf_sha1": "87d2d58d5233", "answer_pdf_sha1": "d9cba2739812", "source_family": "moex-gov-tw", "moex": {"exam_code": "113100", "c": "109", "s": "0901", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "眼球解剖生理學與倫理法規", "year": "113", "exam_name": "113年第二次專技人員高等考試營養師、護理師、社會工作師考試、113年專技人員高等考試心理師、法醫師、語言治療師、聽力師、牙體技術師、公共衛...", "original_question_number": 24, "answer_corrected": false, "flags": [], "slug": "optometrist", "db_exam_id": "optometrist"}'::jsonb, NULL),
  ('optometrist-moex-00330', 'optometrist', 'optometrist-moex-113-b0a2f330', 'sub-optometrist-02', NULL, 'single_choice', '眼動脈有許多分支，但不包括下列何者？', '["睫狀動脈（ciliaryartery）", "視網膜中央動脈（centralretinalartery）", "淚腺動脈（lacrimalartery）", "上頜動脈（maxillaryartery）"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:40+00:00", "source_pdf_sha1": "87d2d58d5233", "answer_pdf_sha1": "d9cba2739812", "source_family": "moex-gov-tw", "moex": {"exam_code": "113100", "c": "109", "s": "0901", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "眼球解剖生理學與倫理法規", "year": "113", "exam_name": "113年第二次專技人員高等考試營養師、護理師、社會工作師考試、113年專技人員高等考試心理師、法醫師、語言治療師、聽力師、牙體技術師、公共衛...", "original_question_number": 25, "answer_corrected": false, "flags": [], "slug": "optometrist", "db_exam_id": "optometrist"}'::jsonb, NULL),
  ('optometrist-moex-00331', 'optometrist', 'optometrist-moex-113-b0a2f330', 'sub-optometrist-02', NULL, 'single_choice', '淚水反射（tearreflex）其神經傳遞路徑不包含下列何者？', '["動眼神經（oculomotornerve）", "三叉神經（trigeminalnerve）", "淚神經（lacrimalnerve）", "大淺岩神經（greatersuperficialpetrosalnerve）"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:40+00:00", "source_pdf_sha1": "87d2d58d5233", "answer_pdf_sha1": "d9cba2739812", "source_family": "moex-gov-tw", "moex": {"exam_code": "113100", "c": "109", "s": "0901", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "眼球解剖生理學與倫理法規", "year": "113", "exam_name": "113年第二次專技人員高等考試營養師、護理師、社會工作師考試、113年專技人員高等考試心理師、法醫師、語言治療師、聽力師、牙體技術師、公共衛...", "original_question_number": 26, "answer_corrected": false, "flags": [], "slug": "optometrist", "db_exam_id": "optometrist"}'::jsonb, NULL),
